"use client";

import { useState, useEffect, useCallback } from "react";
import { supabase } from "@/lib/supabase";
import Link from "next/link";
import { 
  Plus, MapPin, Users, AlertCircle, CheckCircle, UserPlus, 
  Loader2, Building2, ArrowRight, Sparkles, TrendingUp 
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import type { BairroComEstatisticas } from "@/types";
import { TIPOS_PROBLEMAS, STATUS_OPCOES } from "@/types";

export default function HomePage() {
  const [bairros, setBairros] = useState<BairroComEstatisticas[]>([]);
  const [loading, setLoading] = useState(true);
  const [novoBairroOpen, setNovoBairroOpen] = useState(false);
  const [novoMoradorOpen, setNovoMoradorOpen] = useState(false);
  const [bairroSelecionado, setBairroSelecionado] = useState<BairroComEstatisticas | null>(null);
  const [salvando, setSalvando] = useState(false);
  const { toast } = useToast();

  const [formBairro, setFormBairro] = useState({ nome: "", descricao: "", cidade: "" });
  const [imagemBairro, setImagemBairro] = useState<File | null>(null);
  const [previewImagem, setPreviewImagem] = useState<string>("");
  const [formMorador, setFormMorador] = useState<Record<string, string>>({ status: "Pendente" });

  const fetchBairros = useCallback(async () => {
    try {
      setLoading(true);
      
      // Verificar se o Supabase está configurado
      if (!process.env.NEXT_PUBLIC_SUPABASE_URL || !process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY) {
        console.warn("Supabase não configurado. Verifique as variáveis de ambiente.");
        setBairros([]);
        return;
      }

      const { data: bairrosData, error: bairrosError } = await supabase
        .from("bairros")
        .select("*")
        .order("created_at", { ascending: false });

      if (bairrosError) {
        console.error("Erro ao buscar bairros:", bairrosError);
        setBairros([]);
        return;
      }

      const { data: registrosData, error: registrosError } = await supabase
        .from("registros")
        .select("*")
        .eq("categoria", "residentes")
        .eq("secao", "Moradores");

      if (registrosError) {
        console.error("Erro ao buscar registros:", registrosError);
      }

      const bairrosComStats: BairroComEstatisticas[] = (bairrosData || []).map((bairro) => {
        const registrosDoBairro = (registrosData || []).filter(r => r.bairro_id === bairro.id);
        const total_moradores = registrosDoBairro.length;
        const problemas_pendentes = registrosDoBairro.filter(r => 
          !r.status || r.status === "Pendente" || r.status === "Em análise"
        ).length;
        const problemas_resolvidos = registrosDoBairro.filter(r => 
          r.status === "Resolvido"
        ).length;

        // Safely get moradores
        const ultimos_moradores: { nome: string; id: string }[] = [];
        const sorted = [...registrosDoBairro].sort((a, b) => {
          const dateA = new Date(a.created_at || 0).getTime();
          const dateB = new Date(b.created_at || 0).getTime();
          return dateB - dateA;
        });
        
        for (let i = 0; i < Math.min(3, sorted.length); i++) {
          const r = sorted[i];
          let nome = "Sem nome";
          if (r.dados && typeof r.dados === 'object') {
            const dados = r.dados as Record<string, unknown>;
            if (dados.nome && typeof dados.nome === 'string') {
              nome = dados.nome;
            }
          }
          ultimos_moradores.push({ nome, id: r.id });
        }

        // Safely get problemas
        const todosProblemas: string[] = [];
        registrosDoBairro.forEach(r => {
          if (r.dados && typeof r.dados === 'object') {
            const dados = r.dados as Record<string, unknown>;
            if (dados.problemas && typeof dados.problemas === 'string') {
              dados.problemas.split(", ").forEach((p) => {
                if (p && p.trim()) todosProblemas.push(p.trim());
              });
            }
          }
        });
        const tipos_problemas = [...new Set(todosProblemas)].slice(0, 4);

        return {
          ...bairro,
          descricao: bairro.descricao ?? undefined,
          imagem_url: bairro.imagem_url ?? undefined,
          cidade: bairro.cidade ?? undefined,
          estado: bairro.estado ?? undefined,
          total_moradores,
          problemas_pendentes,
          problemas_resolvidos,
          ultimos_moradores,
          tipos_problemas,
        };
      });

      setBairros(bairrosComStats);
    } catch (err) {
      console.error(err);
      setBairros([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchBairros();
  }, [fetchBairros]);

  const handleImagemChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        toast({
          title: "Arquivo muito grande",
          description: "A imagem deve ter no máximo 5MB.",
          variant: "destructive",
        });
        return;
      }
      setImagemBairro(file);
      setPreviewImagem(URL.createObjectURL(file));
    }
  };

  const criarBairro = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formBairro.nome.trim()) return;

    try {
      setSalvando(true);
      let imagem_url = null;
      if (imagemBairro) {
        const fileExt = imagemBairro.name.split('.').pop();
        const fileName = `${Date.now()}_${Math.random().toString(36).substring(7)}.${fileExt}`;
        const filePath = `bairros/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('imagens')
          .upload(filePath, imagemBairro);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('imagens')
          .getPublicUrl(filePath);

        imagem_url = publicUrl;
      }

      const { error } = await supabase.from("bairros").insert({
        nome: formBairro.nome,
        descricao: formBairro.descricao || null,
        cidade: formBairro.cidade || null,
        imagem_url,
      });

      if (error) throw error;

      toast({
        title: "✨ Bairro criado!",
        description: `${formBairro.nome} foi adicionado com sucesso.`,
      });

      setFormBairro({ nome: "", descricao: "", cidade: "" });
      setImagemBairro(null);
      setPreviewImagem("");
      setNovoBairroOpen(false);
      fetchBairros();
    } catch (err) {
      console.error(err);
      toast({
        title: "Erro ao criar bairro",
        description: "Tente novamente mais tarde.",
        variant: "destructive",
      });
    } finally {
      setSalvando(false);
    }
  };

  const criarMorador = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!bairroSelecionado || !formMorador.nome?.trim() || !formMorador.endereco?.trim()) {
      toast({
        title: "Campos obrigatórios",
        description: "Nome e endereço são obrigatórios.",
        variant: "destructive",
      });
      return;
    }

    try {
      setSalvando(true);
      const { error } = await supabase.from("registros").insert({
        bairro_id: bairroSelecionado.id,
        categoria: "residentes",
        secao: "Moradores",
        dados: formMorador,
        status: formMorador.status || "Pendente",
      });

      if (error) throw error;

      toast({
        title: "🎉 Morador cadastrado!",
        description: `${formMorador.nome} foi adicionado a ${bairroSelecionado.nome}.`,
      });

      setFormMorador({ status: "Pendente" });
      setNovoMoradorOpen(false);
      setBairroSelecionado(null);
      fetchBairros();
    } catch (err) {
      console.error(err);
      toast({
        title: "Erro ao cadastrar",
        description: "Tente novamente mais tarde.",
        variant: "destructive",
      });
    } finally {
      setSalvando(false);
    }
  };

  const abrirFormMorador = (bairro: BairroComEstatisticas) => {
    setBairroSelecionado(bairro);
    setFormMorador({ status: "Pendente" });
    setNovoMoradorOpen(true);
  };

  const toggleProblema = (tipo: string) => {
    const current = formMorador.problemas ? formMorador.problemas.split(", ") : [];
    if (current.includes(tipo)) {
      setFormMorador({...formMorador, problemas: current.filter(p => p !== tipo).join(", ")});
    } else {
      setFormMorador({...formMorador, problemas: [...current, tipo].join(", ")});
    }
  };

  const totalMoradores = bairros.reduce((acc, b) => acc + b.total_moradores, 0);
  const totalProblemas = bairros.reduce((acc, b) => acc + b.problemas_pendentes, 0);
  const totalResolvidos = bairros.reduce((acc, b) => acc + b.problemas_resolvidos, 0);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-blue-50">
        <div className="text-center">
          <div className="relative">
            <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-blue-500 to-purple-600 animate-pulse" />
            <Loader2 className="h-8 w-8 animate-spin text-white absolute inset-0 m-auto" />
          </div>
          <p className="mt-4 text-slate-500 font-medium">Carregando...</p>
        </div>
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-gradient-to-br from-slate-50 via-white to-blue-50 hero-pattern">
      {/* Floating Blobs */}
      <div className="fixed inset-0 overflow-hidden pointer-events-none">
        <div className="blob w-96 h-96 bg-purple-300/30 -top-20 -left-20" />
        <div className="blob w-80 h-80 bg-blue-300/30 top-1/3 right-0 animation-delay-2000" />
        <div className="blob w-72 h-72 bg-pink-300/30 bottom-0 left-1/3 animation-delay-4000" />
      </div>

      <div className="relative max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
        {/* Header Section */}
        <header className="mb-12 animate-fade-in-up">
          <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <div className="p-2 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl shadow-lg">
                  <Building2 className="h-6 w-6 text-white" />
                </div>
                <span className="text-sm font-semibold text-blue-600 uppercase tracking-wider">Sistema de Gestão</span>
              </div>
              <h1 className="text-5xl font-bold bg-gradient-to-r from-slate-900 via-slate-700 to-slate-900 bg-clip-text text-transparent">
                Perfil Gestão
              </h1>
              <p className="text-slate-500 mt-2 text-lg">Gerencie bairros, moradores e serviços públicos</p>
            </div>
            
            <Dialog open={novoBairroOpen} onOpenChange={setNovoBairroOpen}>
              <DialogTrigger asChild>
                <Button className="gap-2 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white shadow-lg shadow-blue-500/25 hover:shadow-blue-500/40 transition-all btn-shine rounded-xl px-6 py-6">
                  <Plus className="h-5 w-5" />
                  Novo Bairro
                </Button>
              </DialogTrigger>
              <DialogContent className="max-w-md rounded-2xl">
                <DialogHeader>
                  <DialogTitle className="text-2xl flex items-center gap-2">
                    <Sparkles className="h-5 w-5 text-yellow-500" />
                    Cadastrar Novo Bairro
                  </DialogTitle>
                </DialogHeader>
                <form onSubmit={criarBairro} className="space-y-4 pt-4">
                  <div className="space-y-2">
                    <Label htmlFor="nome">Nome do Bairro *</Label>
                    <Input
                      id="nome"
                      value={formBairro.nome}
                      onChange={(e) => setFormBairro({...formBairro, nome: e.target.value})}
                      placeholder="Ex: Centro"
                      className="rounded-xl"
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="cidade">Cidade</Label>
                    <Input
                      id="cidade"
                      value={formBairro.cidade}
                      onChange={(e) => setFormBairro({...formBairro, cidade: e.target.value})}
                      placeholder="Ex: São Paulo"
                      className="rounded-xl"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="descricao">Descrição</Label>
                    <Textarea
                      id="descricao"
                      value={formBairro.descricao}
                      onChange={(e) => setFormBairro({...formBairro, descricao: e.target.value})}
                      placeholder="Breve descrição do bairro..."
                      rows={3}
                      className="rounded-xl"
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="imagem">Foto do Bairro</Label>
                    <Input
                      id="imagem"
                      type="file"
                      accept="image/*"
                      onChange={handleImagemChange}
                      className="rounded-xl"
                    />
                    {previewImagem && (
                      <img src={previewImagem} alt="Preview" className="w-full h-32 object-cover rounded-xl mt-2" />
                    )}
                  </div>
                  <div className="flex gap-3 pt-2">
                    <Button type="button" variant="outline" className="flex-1 rounded-xl" onClick={() => setNovoBairroOpen(false)}>
                      Cancelar
                    </Button>
                    <Button type="submit" className="flex-1 rounded-xl bg-gradient-to-r from-blue-600 to-purple-600" disabled={salvando}>
                      {salvando && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                      Salvar
                    </Button>
                  </div>
                </form>
              </DialogContent>
            </Dialog>
          </div>
        </header>

        {/* Stats Overview */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-10 animate-fade-in-up stagger-1">
          <div className="stats-card p-6 flex items-center gap-4">
            <div className="p-4 bg-blue-100 rounded-2xl">
              <Users className="h-8 w-8 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">Total de Moradores</p>
              <p className="text-3xl font-bold text-slate-900">{totalMoradores}</p>
            </div>
          </div>
          <div className="stats-card p-6 flex items-center gap-4">
            <div className="p-4 bg-amber-100 rounded-2xl">
              <AlertCircle className="h-8 w-8 text-amber-600" />
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">Problemas Pendentes</p>
              <p className="text-3xl font-bold text-slate-900">{totalProblemas}</p>
            </div>
          </div>
          <div className="stats-card p-6 flex items-center gap-4">
            <div className="p-4 bg-emerald-100 rounded-2xl">
              <CheckCircle className="h-8 w-8 text-emerald-600" />
            </div>
            <div>
              <p className="text-sm text-slate-500 font-medium">Resolvidos</p>
              <p className="text-3xl font-bold text-slate-900">{totalResolvidos}</p>
            </div>
          </div>
        </div>

        {/* Grid de Bairros */}
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {bairros.length > 0 ? (
            bairros.map((bairro, idx) => (
              <Card 
                key={bairro.id} 
                className="overflow-hidden group card-modern opacity-0 animate-fade-in-up"
                style={{ animationDelay: `${(idx + 2) * 0.1}s`, animationFillMode: 'forwards' }}
              >
                <Link href={`/bairro/${bairro.id}`}>
                  <div className="aspect-video w-full relative overflow-hidden">
                    {bairro.imagem_url ? (
                      <img
                        src={bairro.imagem_url}
                        alt={bairro.nome}
                        className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                      />
                    ) : (
                      <div className="w-full h-full bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500 flex items-center justify-center">
                        <MapPin className="h-20 w-20 text-white/30" />
                      </div>
                    )}
                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />
                    <div className="absolute bottom-0 left-0 right-0 p-5">
                      <h2 className="text-2xl font-bold text-white mb-1">{bairro.nome}</h2>
                      {bairro.cidade && (
                        <p className="text-white/80 text-sm flex items-center gap-1.5">
                          <MapPin className="h-4 w-4" />
                          {bairro.cidade}
                        </p>
                      )}
                    </div>
                    <div className="absolute top-4 right-4">
                      <Badge className="bg-white/20 backdrop-blur-md text-white border-0">
                        <TrendingUp className="h-3 w-3 mr-1" />
                        Ativo
                      </Badge>
                    </div>
                  </div>
                </Link>

                <CardContent className="p-6 space-y-5">
                  {/* Estatísticas */}
                  <div className="flex flex-wrap gap-4 text-sm">
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-blue-50 rounded-full">
                      <Users className="h-4 w-4 text-blue-600" />
                      <span className="font-semibold text-blue-900">{bairro.total_moradores}</span>
                      <span className="text-blue-600">moradores</span>
                    </div>
                    {bairro.problemas_pendentes > 0 && (
                      <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 rounded-full">
                        <AlertCircle className="h-4 w-4 text-amber-600" />
                        <span className="font-semibold text-amber-900">{bairro.problemas_pendentes}</span>
                        <span className="text-amber-600">pendentes</span>
                      </div>
                    )}
                    {bairro.problemas_resolvidos > 0 && (
                      <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 rounded-full">
                        <CheckCircle className="h-4 w-4 text-emerald-600" />
                        <span className="font-semibold text-emerald-900">{bairro.problemas_resolvidos}</span>
                        <span className="text-emerald-600">resolvidos</span>
                      </div>
                    )}
                  </div>

                  {/* Últimos Moradores */}
                  {bairro.ultimos_moradores.length > 0 && (
                    <div className="space-y-2">
                      <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Últimos Moradores</p>
                      <div className="space-y-2">
                        {bairro.ultimos_moradores.map((morador) => (
                          <div key={morador.id} className="flex items-center gap-3 text-sm">
                            <div className="w-8 h-8 rounded-full bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center">
                              <span className="text-white font-medium text-xs">{morador.nome.charAt(0).toUpperCase()}</span>
                            </div>
                            <span className="text-slate-700 font-medium truncate">{morador.nome}</span>
                          </div>
                        ))}
                        {bairro.total_moradores > 3 && (
                          <p className="text-xs text-slate-400 pl-11">+{bairro.total_moradores - 3} outros moradores</p>
                        )}
                      </div>
                    </div>
                  )}

                  {/* Tipos de Problemas */}
                  {bairro.tipos_problemas.length > 0 && (
                    <div className="space-y-2">
                      <p className="text-xs font-semibold text-slate-400 uppercase tracking-wider">Problemas Reportados</p>
                      <div className="flex flex-wrap gap-2">
                        {bairro.tipos_problemas.map((tipo, idx) => (
                          <Badge key={idx} className="bg-red-50 text-red-600 border-red-100 hover:bg-red-100">
                            {tipo}
                          </Badge>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Botões de Ação */}
                  <div className="pt-4 flex gap-3">
                    <Button
                      variant="outline"
                      className="flex-1 gap-2 rounded-xl border-emerald-200 text-emerald-600 hover:bg-emerald-50 hover:border-emerald-300 transition-all"
                      onClick={() => abrirFormMorador(bairro)}
                    >
                      <UserPlus className="h-4 w-4" />
                      Morador
                    </Button>
                    <Link href={`/bairro/${bairro.id}`} className="flex-1">
                      <Button className="w-full gap-2 rounded-xl bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white shadow-lg shadow-blue-500/20 group/btn">
                        Painel
                        <ArrowRight className="h-4 w-4 transition-transform group-hover/btn:translate-x-1" />
                      </Button>
                    </Link>
                  </div>
                </CardContent>
              </Card>
            ))
          ) : (
            <div className="col-span-full py-20 text-center animate-fade-in-up">
              <div className="w-24 h-24 mx-auto mb-6 rounded-3xl bg-gradient-to-br from-slate-100 to-slate-200 flex items-center justify-center">
                <MapPin className="h-12 w-12 text-slate-400" />
              </div>
              <h3 className="text-xl font-semibold text-slate-700 mb-2">Nenhum bairro cadastrado</h3>
              <p className="text-slate-400 mb-6">Comece criando seu primeiro bairro para gerenciar</p>
              <Button 
                onClick={() => setNovoBairroOpen(true)}
                className="gap-2 bg-gradient-to-r from-blue-600 to-purple-600 rounded-xl"
              >
                <Plus className="h-4 w-4" />
                Criar Primeiro Bairro
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Modal de Adicionar Morador */}
      <Dialog open={novoMoradorOpen} onOpenChange={setNovoMoradorOpen}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto rounded-2xl">
          <DialogHeader>
            <DialogTitle className="text-2xl flex items-center gap-2">
              <UserPlus className="h-6 w-6 text-blue-500" />
              Adicionar Morador
            </DialogTitle>
            {bairroSelecionado && (
              <p className="text-sm text-slate-500">Bairro: <span className="font-medium text-slate-700">{bairroSelecionado.nome}</span></p>
            )}
          </DialogHeader>
          <form onSubmit={criarMorador} className="space-y-4 pt-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="nome">Nome Completo *</Label>
                <Input
                  id="nome"
                  value={formMorador.nome || ""}
                  onChange={(e) => setFormMorador({...formMorador, nome: e.target.value})}
                  placeholder="Digite o nome"
                  className="rounded-xl"
                  required
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="cpf">CPF</Label>
                <Input
                  id="cpf"
                  value={formMorador.cpf || ""}
                  onChange={(e) => setFormMorador({...formMorador, cpf: e.target.value})}
                  placeholder="000.000.000-00"
                  className="rounded-xl"
                />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="telefone">Telefone</Label>
                <Input
                  id="telefone"
                  value={formMorador.telefone || ""}
                  onChange={(e) => setFormMorador({...formMorador, telefone: e.target.value})}
                  placeholder="(00) 00000-0000"
                  className="rounded-xl"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="data_nascimento">Data de Nascimento</Label>
                <Input
                  id="data_nascimento"
                  type="date"
                  value={formMorador.data_nascimento || ""}
                  onChange={(e) => setFormMorador({...formMorador, data_nascimento: e.target.value})}
                  className="rounded-xl"
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="endereco">Endereço *</Label>
              <Input
                id="endereco"
                value={formMorador.endereco || ""}
                onChange={(e) => setFormMorador({...formMorador, endereco: e.target.value})}
                placeholder="Rua, Avenida..."
                className="rounded-xl"
                required
              />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="numero">Número</Label>
                <Input
                  id="numero"
                  value={formMorador.numero || ""}
                  onChange={(e) => setFormMorador({...formMorador, numero: e.target.value})}
                  placeholder="123"
                  className="rounded-xl"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="complemento">Complemento</Label>
                <Input
                  id="complemento"
                  value={formMorador.complemento || ""}
                  onChange={(e) => setFormMorador({...formMorador, complemento: e.target.value})}
                  placeholder="Apto, Casa..."
                  className="rounded-xl"
                />
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="queixas">Queixas / Problemas</Label>
              <Textarea
                id="queixas"
                value={formMorador.queixas || ""}
                onChange={(e) => setFormMorador({...formMorador, queixas: e.target.value})}
                placeholder="Descreva as queixas..."
                rows={3}
                className="rounded-xl"
              />
            </div>
            <div className="space-y-2">
              <Label>Categorias de Problemas</Label>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-3 p-4 bg-slate-50 rounded-xl border border-slate-100">
                {TIPOS_PROBLEMAS.map((tipo) => (
                  <label key={tipo} className="flex items-center gap-2 cursor-pointer hover:bg-white p-2 rounded-lg transition-colors">
                    <input
                      type="checkbox"
                      className="rounded border-slate-300 w-4 h-4 text-blue-600 focus:ring-blue-500"
                      checked={formMorador.problemas?.includes(tipo) || false}
                      onChange={() => toggleProblema(tipo)}
                    />
                    <span className="text-sm text-slate-700">{tipo}</span>
                  </label>
                ))}
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="status">Status</Label>
              <select
                id="status"
                className="w-full h-11 rounded-xl border border-input bg-background px-4 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                value={formMorador.status || "Pendente"}
                onChange={(e) => setFormMorador({...formMorador, status: e.target.value})}
              >
                {STATUS_OPCOES.map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
            <div className="flex gap-3 pt-4">
              <Button type="button" variant="outline" className="flex-1 rounded-xl" onClick={() => setNovoMoradorOpen(false)}>
                Cancelar
              </Button>
              <Button type="submit" className="flex-1 rounded-xl bg-gradient-to-r from-blue-600 to-purple-600" disabled={salvando}>
                {salvando && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                Salvar Morador
              </Button>
            </div>
          </form>
        </DialogContent>
      </Dialog>
    </main>
  );
}
